import{_ as t,o as a,c as r,a3 as o}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Stripe / Cashier notes","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Stripe / Cashier notes | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/stripe-cashier"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Stripe / Cashier notes | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/stripe-cashier"}]]},"headers":[],"relativePath":"developer-guide/stripe-cashier.md","filePath":"developer-guide/stripe-cashier.md","lastUpdated":1784466015000}'),i={name:"developer-guide/stripe-cashier.md"};function s(n,e,d,c,l,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="stripe-cashier-notes" tabindex="-1">Stripe / Cashier notes <a class="header-anchor" href="#stripe-cashier-notes" aria-label="Permalink to &quot;Stripe / Cashier notes&quot;">​</a></h1><p>Cashier remains installed on the <code>Tenant</code> billable model as the <strong>Stripe gateway driver</strong> — not the business source of truth.</p><h2 id="layering" tabindex="-1">Layering <a class="header-anchor" href="#layering" aria-label="Permalink to &quot;Layering&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Source of truth</th></tr></thead><tbody><tr><td>Licensing</td><td><code>workspace_module_subscriptions</code></td></tr><tr><td>Invoicing / payments</td><td><code>invoices</code>, <code>payments</code> (Billing Engine ledger)</td></tr><tr><td>Stripe mirror</td><td>Cashier <code>subscriptions</code> / <code>subscription_items</code> on <code>Tenant</code></td></tr><tr><td>Credentials</td><td>Encrypted <code>payment_gateways.config</code> (fallback: env <code>STRIPE_*</code>)</td></tr></tbody></table><p>See <a href="/developer-guide/billing-engine">Billing Engine</a> and <a href="/developer-guide/payment-gateways-overview">Payment Gateway Architecture</a>.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li><code>Tenant</code> uses Cashier&#39;s <code>Billable</code> trait (<code>stripe_id</code>, <code>pm_type</code>, <code>pm_last_four</code> are custom columns)</li><li><code>StripeGateway</code> implements <code>PaymentGatewayInterface</code> (checkout, refunds, webhook normalization, testConnection)</li><li><code>ManualGateway</code> is the default driver for synchronous settle</li><li><code>GatewayManager</code> resolves drivers from <code>payment_gateways</code> table + <code>config/core-platform.php</code></li><li>Webhooks: <ul><li><code>POST /stripe/webhook</code> → Cashier + Billing Engine</li><li><code>POST /webhooks/gateways/stripe</code> → Billing Engine only</li></ul></li></ul><h2 id="manual-price-mapping" tabindex="-1">Manual price mapping <a class="header-anchor" href="#manual-price-mapping" aria-label="Permalink to &quot;Manual price mapping&quot;">​</a></h2><p>Modules stay payment-provider agnostic (<code>monthly_price</code>, <code>yearly_price</code>, <code>currency</code>). Stripe Product/Price IDs live in <code>payment_gateway_module_prices</code> (managed under <strong>Payment Gateways → Product Mapping</strong>). The platform never auto-creates Stripe products/prices.</p><h2 id="when-stripe-is-used" tabindex="-1">When Stripe is used <a class="header-anchor" href="#when-stripe-is-used" aria-label="Permalink to &quot;When Stripe is used&quot;">​</a></h2><ul><li>Default gateway = <code>stripe</code>: billable module installs return a Checkout redirect; webhook activates pending subscriptions and settles payments</li><li>Stripe supports recurring (<code>subscriptions</code> capability): provider renewals update the ledger via webhooks; those subscriptions are excluded from platform <code>billing:run-consolidated</code> charge lines</li><li>Default gateway = <code>manual</code>: purchases and consolidated runs mark payments succeeded immediately</li></ul><p>Cashier subscription rows stay in sync for Stripe-backed workspaces but do not drive entitlements.</p>',12)])])}const m=t(i,[["render",s]]);export{h as __pageData,m as default};
